module binary_adder(
  input [7:0] a, // 8-bit binary input number a
  input [7:0] b, // 8-bit binary input number b
  output [8:0] sum // 9-bit binary output number sum
);

  // Initialize carry bit to 0
  assign sum[0] = 0; 

  // Use a for loop to calculate the sum and carry bits for each bit position
  for (int I = 0; I < 8; i++) begin

    // Calculate the sum bit using XOR gate
    assign sum[i+1] = (a[i] ^ b[i]) ^ sum[i];

    // Calculate the carry bit using AND and OR gates
    assign sum[i+1] += (a[i] & b[i]) | (sum[i] & (a[i] ^ b[i]));

