        clientId: client.clientId, 
        scope: scope 
    }; 

    return done(null, token, refreshToken, { 
        expires_in: 3600 
    }); 
})); 

passport.use('bearer', new OAuth2Strategy({ 
    authorizationURL: '/oauth2/authorize', 
    tokenURL: '/oauth2/token', 
    scope: 'all' 
}, (accessToken, done) => { 
    const session = sessions[accessToken]; 

    if (!session) return done(null, false); 

    const user = users.find((user) => user.id === session.userId); 

    if (!user) return done(null, false); 

    done(null, user); 
})); 

passport.use('client-password', new ClientPasswordStrategy((clientId, clientSecret, done) => { 
    const client = clients.find((client) => { 
        return client.clientId === clientId && client.clientSecret === clientSecret; 
    }); 

    return done(null, client); 
})); 

module.exports = { 
    server: server, 
    passport: passport 
}; 
